from django.contrib.auth import login, logout
from django.contrib.auth.mixins import LoginRequiredMixin
from django.contrib import messages
from django.db.models import Q, ProtectedError
from django.shortcuts import redirect, get_object_or_404
from django.urls import reverse_lazy
from django.views import View
from django.views.generic import ListView, CreateView, UpdateView, DeleteView, TemplateView

from .forms import ProductForm, OrderForm, OrderItemFormSet
from .models import Product, Order, User, Supplier


class RoleRequiredMixin:
    allowed_roles = []

    def dispatch(self, request, *args, **kwargs):
        if not request.user.is_authenticated:
            return redirect('login')
        if self.allowed_roles and request.user.role:
            if request.user.role.name.lower() not in self.allowed_roles:
                messages.error(request, 'У вас нет прав для этого действия.')
                return redirect('product_list')
        elif self.allowed_roles:
            messages.error(request, 'У вас нет прав для этого действия.')
            return redirect('product_list')
        return super().dispatch(request, *args, **kwargs)


class AdminRequiredMixin(RoleRequiredMixin):
    allowed_roles = ['администратор']


class ManagerOrAdminRequiredMixin(RoleRequiredMixin):
    allowed_roles = ['администратор', 'менеджер']


class UserLoginView(TemplateView):
    template_name = 'core/login.html'

    def get(self, request, *args, **kwargs):
        if request.user.is_authenticated:
            return redirect('product_list')
        return super().get(request, *args, **kwargs)

    def post(self, request, *args, **kwargs):
        username = request.POST.get('username', '').strip()
        password = request.POST.get('password', '').strip()
        try:
            user = User.objects.get(username=username)
        except User.DoesNotExist:
            messages.error(request, 'Неверный логин или пароль.')
            return self.render_to_response(self.get_context_data())

        if user.check_password(password):
            login(request, user)
            return redirect('product_list')

        messages.error(request, 'Неверный логин или пароль.')
        return self.render_to_response(self.get_context_data())


class UserLogoutView(View):
    def post(self, request, *args, **kwargs):
        logout(request)
        return redirect('login')


class ProductListView(ListView):
    model = Product
    template_name = 'core/product_list.html'
    context_object_name = 'products'

    def get_queryset(self):
        qs = Product.objects.select_related('category', 'manufacturer', 'supplier')

        user = self.request.user

        if user.is_authenticated and (user.is_admin or user.is_manager):
            q = self.request.GET.get('q', '').strip()
            if q:
                qs = qs.filter(
                    Q(name__icontains=q) |
                    Q(article__icontains=q) |
                    Q(description__icontains=q) |
                    Q(manufacturer__name__icontains=q) |
                    Q(category__name__icontains=q) |
                    Q(supplier__name__icontains=q)
                )

            supplier_id = self.request.GET.get('supplier', '')
            if supplier_id:
                qs = qs.filter(supplier_id=supplier_id)

            sort = self.request.GET.get('sort', '')
            if sort == 'quantity_asc':
                qs = qs.order_by('quantity')
            elif sort == 'quantity_desc':
                qs = qs.order_by('-quantity')

        return qs

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['q'] = self.request.GET.get('q', '')
        ctx['sort'] = self.request.GET.get('sort', '')
        ctx['supplier_id'] = self.request.GET.get('supplier', '')
        ctx['suppliers'] = Supplier.objects.all().order_by('name')
        ctx['total_count'] = Product.objects.count()
        ctx['shown_count'] = ctx['products'].count() if hasattr(ctx['products'], 'count') else len(ctx['products'])
        return ctx


class ProductCreateView(AdminRequiredMixin, CreateView):
    model = Product
    form_class = ProductForm
    template_name = 'core/product_form.html'
    success_url = reverse_lazy('product_list')

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['is_edit'] = False
        return ctx

    def form_valid(self, form):
        messages.success(self.request, 'Товар успешно добавлен.')
        return super().form_valid(form)


class ProductUpdateView(AdminRequiredMixin, UpdateView):
    model = Product
    form_class = ProductForm
    template_name = 'core/product_form.html'
    success_url = reverse_lazy('product_list')

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['is_edit'] = True
        ctx['product_id'] = self.object.pk
        return ctx

    def form_valid(self, form):
        messages.success(self.request, 'Товар успешно обновлён.')
        return super().form_valid(form)


class ProductDeleteView(AdminRequiredMixin, DeleteView):
    model = Product
    template_name = 'core/confirm_delete.html'
    success_url = reverse_lazy('product_list')

    def post(self, request, *args, **kwargs):
        try:
            return super().post(request, *args, **kwargs)
        except ProtectedError:
            messages.error(
                request,
                'Невозможно удалить товар — он используется в заказах.'
            )
            return redirect('product_list')


class OrderListView(ManagerOrAdminRequiredMixin, ListView):
    model = Order
    template_name = 'core/order_list.html'
    context_object_name = 'orders'

    def get_queryset(self):
        return Order.objects.select_related(
            'pickup_point', 'client'
        ).prefetch_related('items__product')


class OrderCreateView(AdminRequiredMixin, CreateView):
    model = Order
    form_class = OrderForm
    template_name = 'core/order_form.html'
    success_url = reverse_lazy('order_list')

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['is_edit'] = False
        if self.request.POST:
            ctx['formset'] = OrderItemFormSet(self.request.POST)
        else:
            ctx['formset'] = OrderItemFormSet()
        return ctx

    def form_valid(self, form):
        ctx = self.get_context_data()
        formset = ctx['formset']
        if formset.is_valid():
            self.object = form.save()
            formset.instance = self.object
            formset.save()
            messages.success(self.request, 'Заказ успешно создан.')
            return redirect(self.success_url)
        return self.form_invalid(form)


class OrderUpdateView(AdminRequiredMixin, UpdateView):
    model = Order
    form_class = OrderForm
    template_name = 'core/order_form.html'
    success_url = reverse_lazy('order_list')

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['is_edit'] = True
        ctx['order_id'] = self.object.pk
        if self.request.POST:
            ctx['formset'] = OrderItemFormSet(self.request.POST, instance=self.object)
        else:
            ctx['formset'] = OrderItemFormSet(instance=self.object)
        return ctx

    def form_valid(self, form):
        ctx = self.get_context_data()
        formset = ctx['formset']
        if formset.is_valid():
            self.object = form.save()
            formset.save()
            messages.success(self.request, 'Заказ успешно обновлён.')
            return redirect(self.success_url)
        return self.form_invalid(form)


class OrderDeleteView(AdminRequiredMixin, DeleteView):
    model = Order
    template_name = 'core/confirm_delete.html'
    success_url = reverse_lazy('order_list')
